def parse(input: str) -> list[list[str]]:
    lines = input.split("\n")
    return [list(line) for line in lines]

# Fill in the map first
#   Iterate from top to bottom, left to right
#   empty space is converted if:
#       one above is a beam
#       OR has a splitter to the left or right, with a beam above it
def solve(grid: list[list[str]]) -> int:
    split_beams(grid)
    return num_splits(grid)

def split_beams(grid: list[list[str]]) -> None:
    # First, convert the S to a | for simplicity
    for c in range(len(grid[0])):
        if grid[0][c] == 'S':
            grid[0][c] = '|'

    # Then split beams
    for r in range(1, len(grid)):
        for c in range(len(grid[0])):
            if grid[r][c] == '.':
                if (grid[r-1][c] == '|'):
                    grid[r][c] = '|'
                elif c > 0 and grid[r][c-1] == '^' and grid[r-1][c-1] == '|':
                    grid[r][c] = '|'
                elif c < len(grid[0]) - 1 and grid[r][c+1] == '^' and grid[r-1][c+1] == '|':
                    grid[r][c] = '|'
                


def num_splits(grid: list[list[str]]) -> int:
    total = 0
    for r in range(1, len(grid)):
        for c in range(len(grid[0])):
            if grid[r][c] == '^' and grid[r-1][c] == '|':
                total += 1
    return total


### Main ###
print(solve(parse(INPUT)))